mapper.select:
select market_no, market_title, to_char(market_date, 'yyyy-mm-dd') as market_date, market_writer, view_count, sell_addr, sell_price from market_tbl join member_tbl on (market_writer = member_id) where market_status = #{status}
and market_title like '%'||#{searchKeyword}||'%'
and market_writer = #{searchKeyword}
order by market_no desc order by market_no asc order by view_count desc
order by sell_price desc
offset #{page}*#{size} rows fetch next #{size} rows only
